sub mask_phone_number {
    my ($phone_number) = @_;
    my $masked_number = Text::Mask->new(
        pattern => qr/(\d{3})\D*(\d{3})\D*(\d{4})/,
        replacement => '$1****$3',
    );
    return $masked_number->mask($phone_number);
}

